using UnityEngine;

/// <summary>
/// Rigidbody tabanlı temel hareket sistemi.
/// WASD + joystick destekler. Fizik dostu, FixedUpdate ile çalışır.
/// </summary>
[RequireComponent(typeof(Rigidbody))]
public class PlayerMovement : MonoBehaviour
{
    [Header("Hareket Ayarları")]
    [SerializeField] private float moveSpeed = 7f;

    private Rigidbody _rb;
    private Vector3 _moveInput;

    private void Awake()
    {
        _rb = GetComponent<Rigidbody>();
        _rb.freezeRotation = true; // Fizik kaynaklı dönmeyi engelle
    }

    private void Update()
    {
        // Input her zaman Update'te okunur
        float h = Input.GetAxisRaw("Horizontal");
        float v = Input.GetAxisRaw("Vertical");
        _moveInput = new Vector3(h, 0f, v).normalized;
    }

    private void FixedUpdate()
    {
        // Fizik işlemi her zaman FixedUpdate'te yapılır
        Vector3 velocity = _moveInput * moveSpeed;
        velocity.y = _rb.linearVelocity.y; // Yerçekimini koru
        _rb.linearVelocity = velocity;
    }
}

using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Generic Object Pool. Prefab bazlı, başlangıçta doldurulur.
/// Kullanım: ObjectPool.Instance.Get(prefab) / ObjectPool.Instance.Return(obj)
/// </summary>
public class ObjectPool : MonoBehaviour
{
    public static ObjectPool Instance { get; private set; }

    private readonly Dictionary<int, Queue<GameObject>> _pools = new();

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }
        Instance = this;
    }

    /// <summary>
    /// Havuzu başlangıçta doldurur. Sahne açılışında çağır.
    /// </summary>
    public void Warmup(GameObject prefab, int count)
    {
        int key = prefab.GetInstanceID();
        if (!_pools.ContainsKey(key))
            _pools[key] = new Queue<GameObject>();

        for (int i = 0; i < count; i++)
        {
            GameObject obj = Instantiate(prefab, transform);
            obj.SetActive(false);
            _pools[key].Enqueue(obj);
        }
    }

    /// <summary>
    /// Havuzdan nesne al. Havuz boşsa yeni üretir (fallback).
    /// </summary>
    public GameObject Get(GameObject prefab, Vector3 pos, Quaternion rot)
    {
        int key = prefab.GetInstanceID();

        if (_pools.TryGetValue(key, out var queue) && queue.Count > 0)
        {
            GameObject obj = queue.Dequeue();
            obj.transform.SetPositionAndRotation(pos, rot);
            obj.SetActive(true);
            return obj;
        }

        // Havuz boş — fallback olarak yeni üret
        return Instantiate(prefab, pos, rot);
    }

    /// <summary>
    /// Nesneyi havuza geri gönder (Destroy yerine).
    /// </summary>
    public void Return(GameObject prefab, GameObject obj)
    {
        obj.SetActive(false);
        int key = prefab.GetInstanceID();

        if (!_pools.ContainsKey(key))
            _pools[key] = new Queue<GameObject>();

        _pools[key].Enqueue(obj);
    }
}

using UnityEngine;

/// <summary>
/// Generic Singleton base class.
/// Kullanım: public class GameManager : Singleton<GameManager> { }
/// Sahne geçişlerinde hayatta kalır (DontDestroyOnLoad).
/// </summary>
public abstract class Singleton<T> : MonoBehaviour where T : MonoBehaviour
{
    public static T Instance { get; private set; }

    protected virtual void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }

        Instance = this as T;
        DontDestroyOnLoad(gameObject);
    }
}

