/// <summary>
/// Oyun genelinde tek instance. Sahne geçişlerinde yaşar.
/// Erişim: GameManager.Instance.CurrentScore
/// </summary>
public class GameManager : Singleton<GameManager>
{
    public int CurrentScore { get; private set; }
    public bool IsGamePaused { get; private set; }

    protected override void Awake()
    {
        base.Awake(); // Singleton kontrolü
    }

    public void AddScore(int amount)
    {
        CurrentScore += amount;
    }

    public void TogglePause()
    {
        IsGamePaused = !IsGamePaused;
        Time.timeScale = IsGamePaused ? 0f : 1f;
    }
}

using UnityEngine;
using System.Collections.Generic;

/// <summary>
/// State interface — her durum bunu implement eder.
/// </summary>
public interface IState
{
    void Enter();
    void Execute(); // Her frame çağrılır
    void Exit();
}

/// <summary>
/// Genel amaçlı State Machine. Herhangi bir GameObject'e eklenebilir.
/// </summary>
public class StateMachine : MonoBehaviour
{
    private IState _currentState;
    private readonly Dictionary<System.Type, IState> _states = new();

    /// <summary>
    /// State Machine'e yeni bir durum kaydeder.
    /// </summary>
    public void AddState(IState state)
    {
        _states[state.GetType()] = state;
    }

    /// <summary>
    /// Belirtilen duruma geçiş yapar.
    /// </summary>
    public void ChangeState<T>() where T : IState
    {
        _currentState?.Exit();

        if (_states.TryGetValue(typeof(T), out var newState))
        {
            _currentState = newState;
            _currentState.Enter();
        }
    }

    private void Update()
    {
        _currentState?.Execute();
    }
}

// ─── Örnek: Düşman AI Durumları ─────────────────────────────

public class IdleState : IState
{
    private readonly Transform _enemy;
    private readonly Transform _player;
    private readonly StateMachine _sm;
    private readonly float _detectRange;

    public IdleState(Transform enemy, Transform player, StateMachine sm, float detectRange)
    {
        _enemy = enemy;
        _player = player;
        _sm = sm;
        _detectRange = detectRange;
    }

    public void Enter() => Debug.Log("Idle: Bekliyorum...");

    public void Execute()
    {
        float dist = Vector3.Distance(_enemy.position, _player.position);
        if (dist < _detectRange)
            _sm.ChangeState<ChaseState>();
    }

    public void Exit() { }
}

public class ChaseState : IState
{
    private readonly Transform _enemy;
    private readonly Transform _player;
    private readonly StateMachine _sm;
    private readonly float _speed;
    private readonly float _attackRange;
    private readonly float _loseRange;

    public ChaseState(Transform enemy, Transform player, StateMachine sm, float speed, float attackRange, float loseRange)
    {
        _enemy = enemy;
        _player = player;
        _sm = sm;
        _speed = speed;
        _attackRange = attackRange;
        _loseRange = loseRange;
    }

    public void Enter() => Debug.Log("Chase: Kovalıyorum!");

    public void Execute()
    {
        float dist = Vector3.Distance(_enemy.position, _player.position);

        if (dist > _loseRange)
        {
            _sm.ChangeState<IdleState>();
            return;
        }

        if (dist < _attackRange)
        {
            _sm.ChangeState<AttackState>();
            return;
        }

        Vector3 dir = (_player.position - _enemy.position).normalized;
        _enemy.position += dir * _speed * Time.deltaTime;
    }

    public void Exit() { }
}

public class AttackState : IState
{
    private readonly StateMachine _sm;

    public AttackState(StateMachine sm)
    {
        _sm = sm;
    }

    public void Enter() => Debug.Log("Attack: Saldırıyorum!");
    public void Execute() { /* Saldırı animasyonu, hasar, cooldown */ }
    public void Exit() { }
}

using System;
using UnityEngine;

/// <summary>
/// Oyuncu sağlık sistemi — event tabanlı.
/// Diğer sistemler (UI, ses, kamera) bu event'leri dinler.
/// </summary>
public class PlayerHealth : MonoBehaviour
{
    [SerializeField] private int maxHealth = 100;

    private int _currentHealth;

    // ─── Events (dışarıdan sadece subscribe olunabilir, Invoke edilemez) ───
    public event Action<int, int> OnHealthChanged; // (current, max)
    public event Action OnPlayerDied;

    private void Awake()
    {
        _currentHealth = maxHealth;
    }

    public void TakeDamage(int amount)
    {
        _currentHealth = Mathf.Max(0, _currentHealth - amount);
        OnHealthChanged?.Invoke(_currentHealth, maxHealth);

        if (_currentHealth <= 0)
            OnPlayerDied?.Invoke();
    }

    public void Heal(int amount)
    {
        _currentHealth = Mathf.Min(maxHealth, _currentHealth + amount);
        OnHealthChanged?.Invoke(_currentHealth, maxHealth);
    }
}

