/// <summary>
/// Herhangi bir silah verisini kullanabilen controller.
/// Farklı silahlar için sadece SO değiştirilir, kod aynı kalır.
/// </summary>
public class WeaponController : MonoBehaviour
{
    [SerializeField] private WeaponData weaponData;

    private int _currentAmmo;
    private float _nextFireTime;

    private void Awake()
    {
        _currentAmmo = weaponData.maxAmmo;
    }

    public void Fire()
    {
        if (Time.time < _nextFireTime || _currentAmmo <= 0)
            return;

        _currentAmmo--;
        _nextFireTime = Time.time + weaponData.fireRate;

        Debug.Log($"{weaponData.weaponName} ateşlendi! Hasar: {weaponData.damage}");
    }

    public void Reload()
    {
        _currentAmmo = weaponData.maxAmmo;
    }
}

using UnityEngine;

/// <summary>
/// Smooth kamera takip sistemi.
/// LateUpdate + Lerp ile titremesiz, yumuşak takip.
/// 3D ve 2D projeler için offset ayarlanabilir.
/// </summary>
public class CameraFollow : MonoBehaviour
{
    [Header("Hedef")]
    [SerializeField] private Transform target;

    [Header("Takip Ayarları")]
    [SerializeField] private Vector3 offset = new Vector3(0f, 10f, -7f);
    [SerializeField] private float smoothSpeed = 8f;

    [Header("Sınırlar (Opsiyonel)")]
    [SerializeField] private bool useBounds;
    [SerializeField] private Vector2 minBounds;
    [SerializeField] private Vector2 maxBounds;

    private void LateUpdate()
    {
        if (target == null) return;

        Vector3 desiredPos = target.position + offset;

        // Sınır kontrolü (opsiyonel)
        if (useBounds)
        {
            desiredPos.x = Mathf.Clamp(desiredPos.x, minBounds.x, maxBounds.x);
            desiredPos.z = Mathf.Clamp(desiredPos.z, minBounds.y, maxBounds.y);
        }

        // Smooth geçiş
        Vector3 smoothedPos = Vector3.Lerp(
            transform.position,
            desiredPos,
            smoothSpeed * Time.deltaTime
        );

        transform.position = smoothedPos;
    }

    /// <summary>
    /// Runtime'da hedefi değiştir (sahne geçişi, araç binme vb.)
    /// </summary>
    public void SetTarget(Transform newTarget)
    {
        target = newTarget;
    }

    /// <summary>
    /// Kamerayı anında hedefe ışınla (sahne başlangıcı için).
    /// </summary>
    public void SnapToTarget()
    {
        if (target != null)
            transform.position = target.position + offset;
    }
}

using UnityEngine;

/// <summary>
/// Raycast kullanım örnekleri — silah, tıklama, zemin algılama.
/// </summary>
public class RaycastExamples : MonoBehaviour
{
    [Header("Silah Ayarları")]
    [SerializeField] private float weaponRange = 50f;
    [SerializeField] private int weaponDamage = 25;
    [SerializeField] private LayerMask hitLayers; // Inspector'dan seç

    [Header("Zemin Kontrolü")]
    [SerializeField] private float groundCheckDist = 1.1f;
    [SerializeField] private LayerMask groundLayer;

    private Camera _mainCam;

    private void Awake()
    {
        _mainCam = Camera.main; // Cache — her frame Camera.main çağırma
    }

    // ─── 1. FPS Silah Atışı ──────────────────────────────────
    public void Shoot()
    {
        Ray ray = new Ray(transform.position, transform.forward);

        if (Physics.Raycast(ray, out RaycastHit hit, weaponRange, hitLayers))
        {
            Debug.Log($"İsabet: {hit.collider.name} (mesafe: {hit.distance:F1}m)");

            // Hasar ver
            if (hit.collider.TryGetComponent<IDamageable>(out var target))
                target.TakeDamage(weaponDamage);

            // İsabet noktasında efekt
            Debug.DrawLine(ray.origin, hit.point, Color.red, 0.5f);
        }
        else
        {
            // Bir şeye isabet etmedi
            Debug.DrawRay(ray.origin, ray.direction * weaponRange, Color.yellow, 0.5f);
        }
    }

    // ─── 2. Mouse Tıklama ile Nesne Seçme ────────────────────
    private void Update()
    {
        if (Input.GetMouseButtonDown(0))
        {
            Ray ray = _mainCam.ScreenPointToRay(Input.mousePosition);

            if (Physics.Raycast(ray, out RaycastHit hit, 100f))
            {
                Debug.Log($"Tıklanan: {hit.collider.name}");
            }
        }
    }

    // ─── 3. Yerde mi Kontrolü (IsGrounded) ───────────────────
    public bool IsGrounded()
    {
        return Physics.Raycast(
            transform.position,
            Vector3.down,
            groundCheckDist,
            groundLayer
        );
    }
}

