/// <summary>
/// Hasar alabilen her nesne bu interface'i implement eder.
/// Silah, tuzak, patlama — hepsi sadece IDamageable bilir.
/// </summary>
public interface IDamageable
{
    void TakeDamage(int amount);
}

/// <summary>
/// Genel amaçlı sağlık sistemi.
/// Oyuncu, düşman, destructible obje — hepsine eklenebilir.
/// </summary>
public class HealthSystem : MonoBehaviour, IDamageable
{
    [Header("Sağlık")]
    [SerializeField] private int maxHealth = 100;

    [Header("Invincibility")]
    [SerializeField] private float invincibilityDuration = 0.5f;

    private int _currentHealth;
    private bool _isInvincible;
    private float _invincibilityTimer;
    private bool _isDead;

    // Events
    public event Action<int, int> OnHealthChanged; // (current, max)
    public event Action OnDied;
    public event Action OnDamageTaken;

    public int CurrentHealth => _currentHealth;
    public int MaxHealth => maxHealth;
    public bool IsDead => _isDead;

    private void Awake()
    {
        _currentHealth = maxHealth;
    }

    private void Update()
    {
        // Invincibility timer
        if (_isInvincible)
        {
            _invincibilityTimer -= Time.deltaTime;
            if (_invincibilityTimer <= 0f)
                _isInvincible = false;
        }
    }

    public void TakeDamage(int amount)
    {
        if (_isDead || _isInvincible) return;

        _currentHealth = Mathf.Max(0, _currentHealth - amount);
        OnHealthChanged?.Invoke(_currentHealth, maxHealth);
        OnDamageTaken?.Invoke();

        // Invincibility başlat
        _isInvincible = true;
        _invincibilityTimer = invincibilityDuration;

        if (_currentHealth <= 0)
            Die();
    }

    public void Heal(int amount)
    {
        if (_isDead) return;

        _currentHealth = Mathf.Min(maxHealth, _currentHealth + amount);
        OnHealthChanged?.Invoke(_currentHealth, maxHealth);
    }

    private void Die()
    {
        _isDead = true;
        OnDied?.Invoke();
    }
}

using UnityEngine;

/// <summary>
/// 2D Platformer Karakter Kontrolcüsü.
/// Rigidbody2D tabanlı — hareket, zıplama, duvar kayma, coyote time.
/// </summary>
[RequireComponent(typeof(Rigidbody2D))]
public class CharacterController2D : MonoBehaviour
{
    [Header("Hareket")]
    [SerializeField] private float moveSpeed = 8f;
    [SerializeField] private float jumpForce = 14f;
    [SerializeField] private float wallSlideSpeed = 2f;

    [Header("Ground Check")]
    [SerializeField] private Transform groundCheck;
    [SerializeField] private float groundCheckRadius = 0.2f;
    [SerializeField] private LayerMask groundLayer;

    [Header("Wall Check")]
    [SerializeField] private Transform wallCheck;
    [SerializeField] private float wallCheckDistance = 0.3f;

    [Header("Game Feel")]
    [SerializeField] private float coyoteTime = 0.15f;
    [SerializeField] private float jumpBufferTime = 0.15f;

    private Rigidbody2D _rb;
    private bool _isGrounded;
    private bool _isTouchingWall;
    private bool _isWallSliding;
    private float _coyoteTimer;
    private float _jumpBufferTimer;

    private void Awake()
    {
        _rb = GetComponent<Rigidbody2D>();
    }

    private void Update()
    {
        // Ground & Wall kontrol
        _isGrounded = Physics2D.OverlapCircle(groundCheck.position, groundCheckRadius, groundLayer);
        _isTouchingWall = Physics2D.Raycast(wallCheck.position, transform.right, wallCheckDistance, groundLayer);

        // Coyote time sayacı
        _coyoteTimer = _isGrounded ? coyoteTime : _coyoteTimer - Time.deltaTime;

        // Jump buffer
        if (Input.GetButtonDown("Jump"))
            _jumpBufferTimer = jumpBufferTime;
        else
            _jumpBufferTimer -= Time.deltaTime;

        // Zıplama koşulu
        if (_jumpBufferTimer > 0f && _coyoteTimer > 0f)
        {
            _rb.linearVelocity = new Vector2(_rb.linearVelocity.x, jumpForce);
            _coyoteTimer = 0f;
            _jumpBufferTimer = 0f;
        }

        // Duvar kayma
        _isWallSliding = _isTouchingWall && !_isGrounded && _rb.linearVelocity.y < 0f;

        // Yüz yönü
        float h = Input.GetAxisRaw("Horizontal");
        if (h > 0.1f)       transform.localScale = new Vector3(1f, 1f, 1f);
        else if (h < -0.1f) transform.localScale = new Vector3(-1f, 1f, 1f);
    }

    private void FixedUpdate()
    {
        float h = Input.GetAxisRaw("Horizontal");

        if (_isWallSliding)
            _rb.linearVelocity = new Vector2(_rb.linearVelocity.x, -wallSlideSpeed);
        else
            _rb.linearVelocity = new Vector2(h * moveSpeed, _rb.linearVelocity.y);
    }

    private void OnDrawGizmosSelected()
    {
        if (groundCheck != null)
        {
            Gizmos.color = Color.green;
            Gizmos.DrawWireSphere(groundCheck.position, groundCheckRadius);
        }
        if (wallCheck != null)
        {
            Gizmos.color = Color.blue;
            Gizmos.DrawRay(wallCheck.position, transform.right * wallCheckDistance);
        }
    }
}

using UnityEngine;

/// <summary>
/// 3D FPS Karakter Kontrolcüsü.
/// CharacterController tabanlı — mouselook, WASD hareketi, zıplama.
/// Kamera: Player'ın child'ı olan Camera objesini Inspector'a sürükle.
/// </summary>
[RequireComponent(typeof(CharacterController))]
public class FPSController : MonoBehaviour
{
    [Header("Hareket")]
    [SerializeField] private float moveSpeed = 6f;
    [SerializeField] private float jumpHeight = 1.5f;
    [SerializeField] private float gravity = -20f;

    [Header("Mouse Look")]
    [SerializeField] private Transform cameraTransform;
    [SerializeField] private float mouseSensitivity = 2f;
    [SerializeField] private float maxLookAngle = 80f;

    private CharacterController _controller;
    private Vector3 _velocity;
    private float _cameraPitch;

    private void Awake()
    {
        _controller = GetComponent<CharacterController>();
        Cursor.lockState = CursorLockMode.Locked;
        Cursor.visible = false;
    }

    private void Update()
    {
        // ── Mouse Look ───────────────────────────────────────
        float mouseX = Input.GetAxis("Mouse X") * mouseSensitivity;
        float mouseY = Input.GetAxis("Mouse Y") * mouseSensitivity;

        _cameraPitch -= mouseY;
        _cameraPitch = Mathf.Clamp(_cameraPitch, -maxLookAngle, maxLookAngle);
        cameraTransform.localRotation = Quaternion.Euler(_cameraPitch, 0f, 0f);
        transform.Rotate(Vector3.up * mouseX);

        // ── WASD Hareketi ────────────────────────────────────
        float h = Input.GetAxisRaw("Horizontal");
        float v = Input.GetAxisRaw("Vertical");
        Vector3 move = (transform.right * h + transform.forward * v).normalized;

        // ── Yerçekimi & Zıplama ──────────────────────────────
        if (_controller.isGrounded)
        {
            _velocity.y = -2f; // Yere yapıştır
            if (Input.GetButtonDown("Jump"))
                _velocity.y = Mathf.Sqrt(jumpHeight * -2f * gravity);
        }

        _velocity.y += gravity * Time.deltaTime;
        _controller.Move((move * moveSpeed + _velocity) * Time.deltaTime);
    }
}

using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Merkezi ses yönetim sistemi.
/// Kullanım: AudioManager.Instance.PlaySFX(clip);
///           AudioManager.Instance.PlayMusic(clip);
/// Singleton<AudioManager> base class'ını gerektirir.
/// </summary>
public class AudioManager : MonoBehaviour
{
    public static AudioManager Instance { get; private set; }

    [Header("Müzik")]
    [SerializeField] private AudioSource musicSource;

    [Header("SFX Pool")]
    [SerializeField] private int sfxPoolSize = 10;

    private readonly Queue<AudioSource> _sfxPool = new();

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;
        DontDestroyOnLoad(gameObject);
        BuildSFXPool();
    }

    private void BuildSFXPool()
    {
        for (int i = 0; i < sfxPoolSize; i++)
        {
            var src = gameObject.AddComponent<AudioSource>();
            src.playOnAwake = false;
            _sfxPool.Enqueue(src);
        }
    }

    // ── SFX ────────────────────────────────────────────────
    public void PlaySFX(AudioClip clip, float volume = 1f, float pitch = 1f)
    {
        if (clip == null) return;
        AudioSource src = GetPooledSource();
        src.clip = clip;
        src.volume = volume;
        src.pitch = pitch;
        src.Play();
        StartCoroutine(ReturnToPool(src, clip.length / pitch));
    }

    public void PlaySFXAtPoint(AudioClip clip, Vector3 position, float volume = 1f)
    {
        if (clip == null) return;
        AudioSource.PlayClipAtPoint(clip, position, volume);
    }

    // ── Müzik ───────────────────────────────────────────────
    public void PlayMusic(AudioClip clip, bool loop = true)
    {
        if (musicSource.clip == clip && musicSource.isPlaying) return;
        musicSource.clip = clip;
        musicSource.loop = loop;
        musicSource.Play();
    }

    public void StopMusic() => musicSource.Stop();

    public void SetMusicVolume(float v) => musicSource.volume = Mathf.Clamp01(v);

    // ── Pool Yardımcıları ───────────────────────────────────
    private AudioSource GetPooledSource()
    {
        if (_sfxPool.Count > 0) return _sfxPool.Dequeue();
        // Havuz boşsa yeni ekle
        var src = gameObject.AddComponent<AudioSource>();
        src.playOnAwake = false;
        return src;
    }

    private IEnumerator ReturnToPool(AudioSource src, float delay)
    {
        yield return new WaitForSeconds(delay + 0.1f);
        src.clip = null;
        _sfxPool.Enqueue(src);
    }
}

