/// <summary>
/// JSON tabanlı Save/Load sistemi.
/// Kullanım: SaveSystem.Save(data) / SaveSystem.Load()
/// </summary>
public static class SaveSystem
{
    private static readonly string SavePath =
        Path.Combine(Application.persistentDataPath, "savegame.json");

    public static void Save(SaveData data)
    {
        data.saveDate = System.DateTime.Now.ToString("yyyy-MM-dd HH:mm");
        string json = JsonUtility.ToJson(data, prettyPrint: true);
        File.WriteAllText(SavePath, json);
        Debug.Log($"[SaveSystem] Kaydedildi: {SavePath}");
    }

    public static SaveData Load()
    {
        if (!File.Exists(SavePath))
        {
            Debug.Log("[SaveSystem] Kayıt dosyası bulunamadı, yeni oyun başlatılıyor.");
            return new SaveData();
        }

        string json = File.ReadAllText(SavePath);
        SaveData data = JsonUtility.FromJson<SaveData>(json);
        Debug.Log($"[SaveSystem] Yüklendi — Tarih: {data.saveDate}");
        return data;
    }

    public static void Delete()
    {
        if (File.Exists(SavePath))
            File.Delete(SavePath);
        Debug.Log("[SaveSystem] Kayıt silindi.");
    }

    public static bool HasSave() => File.Exists(SavePath);
}

