/// <summary>
/// Merkezi UI Panel Yönetim Sistemi.
/// Kullanım: UIManager.Instance.OpenPanel("GameHUD");
///           UIManager.Instance.ClosePanel("PauseMenu");
/// </summary>
public class UIManager : MonoBehaviour
{
    public static UIManager Instance { get; private set; }

    [System.Serializable]
    public struct PanelEntry
    {
        public string name;
        public GameObject panel;
    }

    [SerializeField] private PanelEntry[] panels;
    [SerializeField] private float fadeDuration = 0.25f;

    private readonly Dictionary<string, CanvasGroup> _panelMap = new();
    private readonly Stack<string> _panelHistory = new();

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;

        foreach (var entry in panels)
        {
            if (!entry.panel.TryGetComponent<CanvasGroup>(out var cg))
                cg = entry.panel.AddComponent<CanvasGroup>();

            cg.alpha = 0f;
            cg.interactable = false;
            cg.blocksRaycasts = false;
            _panelMap[entry.name] = cg;
        }
    }

    private void Update()
    {
        // Escape ile bir önceki panele dön
        if (Input.GetKeyDown(KeyCode.Escape) && _panelHistory.Count > 0)
        {
            string prev = _panelHistory.Pop();
            OpenPanel(prev, addToHistory: false);
        }
    }

    public void OpenPanel(string panelName, bool addToHistory = true)
    {
        if (!_panelMap.TryGetValue(panelName, out var cg))
        {
            Debug.LogWarning($"[UIManager] Panel bulunamadı: {panelName}");
            return;
        }

        if (addToHistory && _panelHistory.TryPeek(out var current) && current != panelName)
            _panelHistory.Push(panelName);
        else if (addToHistory)
            _panelHistory.Push(panelName);

        StartCoroutine(Fade(cg, 1f, true));
    }

    public void ClosePanel(string panelName)
    {
        if (!_panelMap.TryGetValue(panelName, out var cg)) return;
        StartCoroutine(Fade(cg, 0f, false));
    }

    public void CloseAll()
    {
        foreach (var cg in _panelMap.Values)
            StartCoroutine(Fade(cg, 0f, false));
        _panelHistory.Clear();
    }

    private IEnumerator Fade(CanvasGroup cg, float targetAlpha, bool interactive)
    {
        float startAlpha = cg.alpha;
        float elapsed = 0f;

        if (interactive)
        {
            cg.interactable = true;
            cg.blocksRaycasts = true;
        }

        while (elapsed < fadeDuration)
        {
            elapsed += Time.unscaledDeltaTime; // Pause menüsü için unscaled
            cg.alpha = Mathf.Lerp(startAlpha, targetAlpha, elapsed / fadeDuration);
            yield return null;
        }

        cg.alpha = targetAlpha;
        if (!interactive)
        {
            cg.interactable = false;
            cg.blocksRaycasts = false;
        }
    }
}

