    public int maxStackSize = 99;
}

/// <summary>
/// Bir envanter slotu — item + miktar.
/// </summary>
[System.Serializable]
public struct InventorySlot
{
    public ItemData item;
    public int amount;

    public InventorySlot(ItemData item, int amount)
    {
        this.item = item;
        this.amount = amount;
    }
}

/// <summary>
/// Envanter yönetim sistemi.
/// Kullanım: inventory.AddItem(itemData, 1);
///           inventory.RemoveItem(itemData, 1);
/// </summary>
public class Inventory : MonoBehaviour
{
    [SerializeField] private int maxSlots = 20;

    public List<InventorySlot> Slots { get; private set; } = new();

    // UI ve diğer sistemler bu event'i dinler
    public event Action OnInventoryChanged;

    public bool AddItem(ItemData item, int amount = 1)
    {
        // Stack desteği: aynı item var mı?
        if (item.isStackable)
        {
            for (int i = 0; i < Slots.Count; i++)
            {
                if (Slots[i].item == item && Slots[i].amount < item.maxStackSize)
                {
                    int addable = Mathf.Min(amount, item.maxStackSize - Slots[i].amount);
                    Slots[i] = new InventorySlot(item, Slots[i].amount + addable);
                    OnInventoryChanged?.Invoke();
                    return true;
                }
            }
        }

        // Yeni slot aç
        if (Slots.Count >= maxSlots)
        {
            Debug.Log("[Inventory] Envanter dolu!");
            return false;
        }

        Slots.Add(new InventorySlot(item, amount));
        OnInventoryChanged?.Invoke();
        return true;
    }

    public bool RemoveItem(ItemData item, int amount = 1)
    {
        for (int i = 0; i < Slots.Count; i++)
        {
            if (Slots[i].item != item) continue;

            if (Slots[i].amount > amount)
            {
                Slots[i] = new InventorySlot(item, Slots[i].amount - amount);
            }
            else
            {
                Slots.RemoveAt(i);
            }

            OnInventoryChanged?.Invoke();
            return true;
        }
        return false;
    }

    public bool HasItem(ItemData item, int amount = 1)
    {
        int total = 0;
        foreach (var slot in Slots)
            if (slot.item == item) total += slot.amount;
        return total >= amount;
    }

    public int GetItemCount(ItemData item)
    {
        int total = 0;
        foreach (var slot in Slots)
            if (slot.item == item) total += slot.amount;
        return total;
    }
}

