    public float spawnInterval = 0.8f;  // Düşmanlar arası saniye
    public float waveBreakDuration = 3f; // Sonraki wave'e kadar bekleme
}

/// <summary>
/// Wave yönetim sistemi.
/// Kullanım: WaveManager sahnede bulunur, otomatik başlar.
/// Düşman scripti ölünce: WaveManager.Instance.EnemyKilled() çağırır.
/// </summary>
public class WaveManager : MonoBehaviour
{
    public static WaveManager Instance { get; private set; }

    [Header("Waves")]
    [SerializeField] private WaveData[] waves;
    [SerializeField] private Transform[] spawnPoints;

    public int CurrentWave { get; private set; } = 0;
    public bool IsWaveActive { get; private set; } = false;

    private int _enemiesAlive = 0;
    private int _enemiesSpawned = 0;

    // UI ve diğer sistemler için event
    public event System.Action<int> OnWaveStarted;   // wave numarası
    public event System.Action<int> OnWaveCompleted; // wave numarası
    public event System.Action OnAllWavesCompleted;

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;
    }

    private void Start() => StartCoroutine(RunWaves());

    private IEnumerator RunWaves()
    {
        for (int i = 0; i < waves.Length; i++)
        {
            CurrentWave = i + 1;
            WaveData wave = waves[i];

            OnWaveStarted?.Invoke(CurrentWave);
            yield return StartCoroutine(SpawnWave(wave));

            // Tüm düşmanlar ölene kadar bekle
            yield return new WaitUntil(() => _enemiesAlive <= 0);

            IsWaveActive = false;
            OnWaveCompleted?.Invoke(CurrentWave);

            // Son wave değilse ara ver
            if (i < waves.Length - 1)
                yield return new WaitForSeconds(wave.waveBreakDuration);
        }
        OnAllWavesCompleted?.Invoke();
    }

    private IEnumerator SpawnWave(WaveData wave)
    {
        IsWaveActive = true;
        _enemiesAlive = wave.enemyCount;
        _enemiesSpawned = 0;

        while (_enemiesSpawned < wave.enemyCount)
        {
            Transform spawnPoint = spawnPoints[Random.Range(0, spawnPoints.Length)];
            Instantiate(wave.enemyPrefab, spawnPoint.position, spawnPoint.rotation);
            _enemiesSpawned++;
            yield return new WaitForSeconds(wave.spawnInterval);
        }
    }

    /// <summary>
    /// Düşman scripti öldüğünde bu metodu çağır.
    /// </summary>
    public void EnemyKilled()
    {
        _enemiesAlive = Mathf.Max(0, _enemiesAlive - 1);
    }
}

