/// Oluştur: Assets > sağ tık > Create > Dialogue > DialogueData
/// </summary>
[CreateAssetMenu(fileName = "Dialogue", menuName = "Dialogue/DialogueData")]
public class DialogueData : ScriptableObject
{
    public DialogueLine[] lines;
}

/// <summary>
/// Merkezi Diyalog Yöneticisi.
/// Kullanım: DialogueManager.Instance.StartDialogue(dialogueData);
/// </summary>
public class DialogueManager : MonoBehaviour
{
    public static DialogueManager Instance { get; private set; }

    [Header("UI Referansları")]
    [SerializeField] private GameObject dialoguePanel;
    [SerializeField] private TextMeshProUGUI speakerText;
    [SerializeField] private TextMeshProUGUI dialogueText;

    [Header("Ayarlar")]
    [SerializeField] private float charDelay = 0.03f; // Typewriter hızı

    public bool IsDialogueActive { get; private set; } = false;

    private DialogueLine[] _lines;
    private int _currentIndex;
    private bool _isTyping;
    private Coroutine _typeCoroutine;

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;
        dialoguePanel.SetActive(false);
    }

    private void Update()
    {
        if (!IsDialogueActive) return;

        if (Input.GetKeyDown(KeyCode.E) || Input.GetKeyDown(KeyCode.Space))
        {
            if (_isTyping)
                SkipTyping(); // Yazımı anında tamamla
            else
                NextLine();   // Sonraki satıra geç
        }
    }

    public void StartDialogue(DialogueData data)
    {
        _lines = data.lines;
        _currentIndex = 0;
        IsDialogueActive = true;
        dialoguePanel.SetActive(true);
        ShowLine(_lines[0]);
    }

    private void ShowLine(DialogueLine line)
    {
        speakerText.text = line.speakerName;
        if (_typeCoroutine != null) StopCoroutine(_typeCoroutine);
        _typeCoroutine = StartCoroutine(TypeText(line.text));
    }

    private IEnumerator TypeText(string text)
    {
        _isTyping = true;
        dialogueText.text = string.Empty;
        foreach (char c in text)
        {
            dialogueText.text += c;
            yield return new WaitForSeconds(charDelay);
        }
        _isTyping = false;
    }

    private void SkipTyping()
    {
        if (_typeCoroutine != null) StopCoroutine(_typeCoroutine);
        dialogueText.text = _lines[_currentIndex].text;
        _isTyping = false;
    }

    private void NextLine()
    {
        _currentIndex++;
        if (_currentIndex >= _lines.Length)
        {
            EndDialogue();
            return;
        }
        ShowLine(_lines[_currentIndex]);
    }

    private void EndDialogue()
    {
        IsDialogueActive = false;
        dialoguePanel.SetActive(false);
    }
}

using System.Collections;
using UnityEngine;
using UnityEngine.SceneManagement;
using UnityEngine.UI;

/// <summary>
/// Sahne yöneticisi — async loading + loading screen desteği.
/// Kullanım: SceneLoader.Instance.LoadScene("GameScene");
/// </summary>
public class SceneLoader : MonoBehaviour
{
    public static SceneLoader Instance { get; private set; }

    [Header("Loading UI")]
    [SerializeField] private GameObject loadingScreen;
    [SerializeField] private Slider progressBar;

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;
        DontDestroyOnLoad(gameObject);
    }

    /// <summary>Sahneyi async olarak yükler, loading screen gösterir.</summary>
    public void LoadScene(string sceneName)
    {
        StartCoroutine(LoadSceneAsync(sceneName));
    }

    public void LoadScene(int buildIndex)
    {
        StartCoroutine(LoadSceneAsync(buildIndex));
    }

    /// <summary>Mevcut sahneyi yeniden yükle (retry / restart).</summary>
    public void ReloadCurrentScene()
    {
        LoadScene(SceneManager.GetActiveScene().buildIndex);
    }

    /// <summary>Bir sonraki sahneye geç.</summary>
    public void LoadNextScene()
    {
        int next = SceneManager.GetActiveScene().buildIndex + 1;
        if (next < SceneManager.sceneCountInBuildSettings)
            LoadScene(next);
        else
            Debug.LogWarning("SceneLoader: Son sahnedeyiz, sonraki sahne yok.");
    }

    private IEnumerator LoadSceneAsync(string sceneName)
    {
        yield return StartCoroutine(RunLoadingScreen(SceneManager.LoadSceneAsync(sceneName)));
    }

    private IEnumerator LoadSceneAsync(int buildIndex)
    {
        yield return StartCoroutine(RunLoadingScreen(SceneManager.LoadSceneAsync(buildIndex)));
    }

    private IEnumerator RunLoadingScreen(AsyncOperation operation)
    {
        operation.allowSceneActivation = false;

        if (loadingScreen != null) loadingScreen.SetActive(true);

        while (!operation.isDone)
        {
            // progress 0 → 0.9 arası gider; 1f'e normalize et
            float progress = Mathf.Clamp01(operation.progress / 0.9f);

            if (progressBar != null) progressBar.value = progress;

            // Sahne hazır (0.9), aktifleştir
            if (operation.progress >= 0.9f)
            {
                if (progressBar != null) progressBar.value = 1f;
                yield return new WaitForSeconds(0.2f); // Kısa bekleme — kullanıcı %100 görsün
                operation.allowSceneActivation = true;
            }

            yield return null;
        }

        if (loadingScreen != null) loadingScreen.SetActive(false);
    }
}

using UnityEngine;
