/// <summary>
/// Yeni Unity Input System ile hareket + zıplama + ateş.
/// Gereksinim: Package Manager'dan Input System kurulu olmalı.
/// Inspector'da PlayerInput component'e .inputactions asset'ini bağla.
/// </summary>
[RequireComponent(typeof(Rigidbody2D))]
public class PlayerInputHandler : MonoBehaviour
{
    [Header("Hareket")]
    [SerializeField] private float moveSpeed = 7f;
    [SerializeField] private float jumpForce = 12f;

    [Header("Ateş")]
    [SerializeField] private GameObject bulletPrefab;
    [SerializeField] private Transform firePoint;

    private Rigidbody2D _rb;
    private Vector2 _moveInput;
    private bool _isGrounded;

    // ─── Input Callbacks (PlayerInput tarafından çağrılır) ────────────────────

    /// <summary>Action adı "Move" olan action'ın callback'i.</summary>
    public void OnMove(InputValue value)
    {
        _moveInput = value.Get<Vector2>();
    }

    /// <summary>Action adı "Jump" olan action'ın callback'i.</summary>
    public void OnJump(InputValue value)
    {
        if (value.isPressed && _isGrounded)
        {
            _rb.AddForce(Vector2.up * jumpForce, ForceMode2D.Impulse);
        }
    }

    /// <summary>Action adı "Fire" olan action'ın callback'i.</summary>
    public void OnFire(InputValue value)
    {
        if (value.isPressed && bulletPrefab != null && firePoint != null)
        {
            Instantiate(bulletPrefab, firePoint.position, firePoint.rotation);
        }
    }

    // ─── Unity Lifecycle ──────────────────────────────────────────────────────

    private void Awake()
    {
        _rb = GetComponent<Rigidbody2D>();
    }

    private void FixedUpdate()
    {
        _rb.linearVelocity = new Vector2(_moveInput.x * moveSpeed, _rb.linearVelocity.y);
    }

    private void OnCollisionEnter2D(Collision2D col)
    {
        if (col.gameObject.CompareTag("Ground")) _isGrounded = true;
    }

    private void OnCollisionExit2D(Collision2D col)
    {
        if (col.gameObject.CompareTag("Ground")) _isGrounded = false;
    }
}

