        if (Input.GetKey(fireKey) && Time.time >= _nextFireTime)
        {
            Fire();
            _nextFireTime = Time.time + (1f / fireRate);
        }
    }

    private void Fire()
    {
        if (bulletPrefab == null || firePoint == null) return;
        GameObject bullet = Instantiate(bulletPrefab, firePoint.position, firePoint.rotation);
        // İpucu: Object Pool kullanıyorsan Instantiate yerine pool.Get() çağır
    }
}

/// <summary>
/// Mermi hareketi + hasar + yaşam süresi.
/// </summary>
[RequireComponent(typeof(Rigidbody2D))]
public class Projectile : MonoBehaviour
{
    [Header("Mermi Ayarları")]
    [SerializeField] private float speed = 20f;
    [SerializeField] private float lifetime = 3f;   // Saniye
    [SerializeField] private int damage = 10;
    [SerializeField] private string targetTag = "Enemy";

    private Rigidbody2D _rb;

    private void Awake()
    {
        _rb = GetComponent<Rigidbody2D>();
    }

    private void OnEnable()
    {
        // Pool'dan alındığında yönü ve hızı ayarla
        _rb.linearVelocity = transform.up * speed; // 2D: transform.up = "ileri"
        Invoke(nameof(Deactivate), lifetime);       // Yaşam süresi
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag(targetTag)) return;

        // Hasar ver
        if (other.TryGetComponent<HealthSystem>(out var health))
        {
            health.TakeDamage(damage);
        }

        Deactivate();
    }

    private void Deactivate()
    {
        CancelInvoke(nameof(Deactivate));
        _rb.linearVelocity = Vector2.zero;
        gameObject.SetActive(false); // Pool'a geri döner
        // Object Pool kullanmıyorsan: Destroy(gameObject);
    }
}

