// ─── Pickup Veri Tipleri ──────────────────────────────────────────────────────

public enum PickupType { Coin, Health, Ammo, SpeedBoost, Shield }

/// <summary>
/// Pickup verisi — ScriptableObject.
/// Oluştur: Assets > sağ tık > Create > Pickup > PickupData
/// </summary>
[CreateAssetMenu(fileName = "PickupData", menuName = "Pickup/PickupData")]
public class PickupData : ScriptableObject
{
    public PickupType type;
    public int value = 1;            // Coin: +1 puan, Health: +25 can, vb.
    public float duration = 0f;      // Geçici efektler için (0 = kalıcı)
    public AudioClip pickupSound;
    public GameObject pickupEffect;  // Particle prefab
}

// ─── Pickup Bileşeni ──────────────────────────────────────────────────────────

/// <summary>
/// Sahneye yerleştirilen toplanabilir nesne.
/// Inspector'da PickupData ata. Collider 'Is Trigger' olmalı.
/// </summary>
public class Pickup : MonoBehaviour
{
    [SerializeField] private PickupData data;
    [SerializeField] private float bobHeight = 0.15f;  // Yukarı-aşağı sallanma
    [SerializeField] private float bobSpeed  = 2f;
    [SerializeField] private float rotateSpeed = 90f;  // Derece/saniye

    private Vector3 _startPos;

    private void Start()
    {
        _startPos = transform.position;
    }

    private void Update()
    {
        // Yüzer animasyon
        float y = _startPos.y + Mathf.Sin(Time.time * bobSpeed) * bobHeight;
        transform.position = new Vector3(transform.position.x, y, transform.position.z);
        transform.Rotate(0f, rotateSpeed * Time.deltaTime, 0f);
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;
        ApplyEffect(other.gameObject);
        SpawnEffects();
        gameObject.SetActive(false); // Veya Destroy(gameObject);
    }

    private void ApplyEffect(GameObject player)
    {
        switch (data.type)
        {
            case PickupType.Coin:
                // GameManager.Instance.AddScore(data.value);
                Debug.Log($"+{data.value} coin");
                break;

            case PickupType.Health:
                if (player.TryGetComponent<HealthSystem>(out var hp))
                    hp.Heal(data.value);
                break;

            case PickupType.SpeedBoost:
                // PlayerMovement'e geçici hız artışı ver
                // player.GetComponent<PlayerMovement>().ApplySpeedBoost(data.value, data.duration);
                Debug.Log($"Speed boost: +{data.value} for {data.duration}s");
                break;

            default:
                Debug.Log($"Pickup: {data.type} x{data.value}");
                break;
        }
    }

    private void SpawnEffects()
    {
        if (data.pickupEffect != null)
            Instantiate(data.pickupEffect, transform.position, Quaternion.identity);

        if (data.pickupSound != null)
            AudioSource.PlayClipAtPoint(data.pickupSound, transform.position);
    }
}

using UnityEngine;

/// <summary>
/// Animator yöneticisi — hash tabanlı, GC-free parameter güncellemeleri.
/// </summary>
[RequireComponent(typeof(Animator))]
[RequireComponent(typeof(Rigidbody2D))]
public class PlayerAnimator : MonoBehaviour
{
    // ─── Bileşenler ───────────────────────────────────────────────────────────
    private Animator _anim;
    private Rigidbody2D _rb;

    // ─── Animator Parameter Hash'leri (string lookup GC'sini önler) ──────────
    private static readonly int _hashSpeed     = Animator.StringToHash("Speed");
    private static readonly int _hashIsGrounded = Animator.StringToHash("IsGrounded");
    private static readonly int _hashJump      = Animator.StringToHash("Jump");
    private static readonly int _hashHurt      = Animator.StringToHash("Hurt");
    private static readonly int _hashDead      = Animator.StringToHash("Dead");

    // ─── Durum ────────────────────────────────────────────────────────────────
    private bool _isGrounded;

    private void Awake()
    {
        _anim = GetComponent<Animator>();
        _rb   = GetComponent<Rigidbody2D>();
    }

    private void Update()
    {
        UpdateMovementAnim();
        UpdateGroundedAnim();
    }

    // ─── Public API ───────────────────────────────────────────────────────────

    /// <summary>Zıplama animasyonunu tetikle.</summary>
    public void TriggerJump()
    {
        _anim.SetTrigger(_hashJump);
    }

    /// <summary>Hasar alma animasyonunu tetikle.</summary>
    public void TriggerHurt()
    {
        _anim.SetTrigger(_hashHurt);
    }

    /// <summary>Ölüm animasyonunu başlat.</summary>
    public void TriggerDead()
    {
        _anim.SetBool(_hashDead, true);
    }

    // ─── İç Güncellemeler ────────────────────────────────────────────────────

    private void UpdateMovementAnim()
    {
        // Yatay hız büyüklüğünü Blend Tree parametresine gönder
        float speed = Mathf.Abs(_rb.linearVelocity.x);
        _anim.SetFloat(_hashSpeed, speed);

        // Sprite yönü — koşma yönüne göre çevir
        if (_rb.linearVelocity.x > 0.1f)
            transform.localScale = new Vector3(1f, 1f, 1f);
        else if (_rb.linearVelocity.x < -0.1f)
            transform.localScale = new Vector3(-1f, 1f, 1f);
    }

    private void UpdateGroundedAnim()
    {
        _anim.SetBool(_hashIsGrounded, _isGrounded);
    }

    // ─── Ground Detection ─────────────────────────────────────────────────────

    private void OnCollisionEnter2D(Collision2D col)
    {
        if (col.gameObject.CompareTag("Ground")) _isGrounded = true;
    }

    private void OnCollisionExit2D(Collision2D col)
    {
        if (col.gameObject.CompareTag("Ground")) _isGrounded = false;
    }
}

using UnityEngine;

/// <summary>
/// Tek parallax katmanı.
/// Her arka plan sprite'ına ekle, Inspector'da parallaxFactor ayarla.
/// </summary>
public class ParallaxLayer : MonoBehaviour
{
    [Header("Parallax Ayarları")]
    [Tooltip("0 = kamerayla aynı hız (ön plan), 1 = tamamen sabit (arka plan)")]
    [Range(0f, 1f)]
    [SerializeField] private float parallaxFactor = 0.5f;

    [Header("Sonsuz Scroll")]
    [SerializeField] private bool infiniteHorizontal = true;
    [SerializeField] private bool infiniteVertical   = false;

    private Transform _cam;
    private Vector3   _lastCamPos;
    private float     _spriteWidth;
    private float     _spriteHeight;

    private void Start()
    {
        _cam        = Camera.main.transform;
        _lastCamPos = _cam.position;

        var sr = GetComponent<SpriteRenderer>();
        if (sr != null)
        {
            _spriteWidth  = sr.bounds.size.x;
            _spriteHeight = sr.bounds.size.y;
        }
    }

    private void LateUpdate()
    {
        // Kameranın bu frame'deki hareketi
        Vector3 delta = _cam.position - _lastCamPos;

        // Parallax'lı pozisyon hesapla
        transform.position += new Vector3(
            delta.x * (1f - parallaxFactor),
            delta.y * (1f - parallaxFactor),
            0f
        );

        _lastCamPos = _cam.position;

        // ─── Sonsuz Scroll ─────────────────────────────────────────────────────
        if (infiniteHorizontal && _spriteWidth > 0f)
        {
            float distX = _cam.position.x - transform.position.x;
            if (Mathf.Abs(distX) >= _spriteWidth)
            {
                // Sprite genişliği kadar kaydır — seamless tekrar
                transform.position += new Vector3(
                    Mathf.Sign(distX) * _spriteWidth, 0f, 0f
                );
            }
        }

        if (infiniteVertical && _spriteHeight > 0f)
        {
            float distY = _cam.position.y - transform.position.y;
            if (Mathf.Abs(distY) >= _spriteHeight)
            {
                transform.position += new Vector3(
                    0f, Mathf.Sign(distY) * _spriteHeight, 0f
                );
            }
        }
    }
}

using System;
using TMPro;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Çok amaçlı zamanlayıcı — countdown, stopwatch ve cooldown desteği.
/// </summary>
public class GameTimer : MonoBehaviour
{
    public enum TimerMode { Countdown, Stopwatch }

    [Header("Ayarlar")]
    [SerializeField] private TimerMode mode = TimerMode.Countdown;
    [SerializeField] private float startTime = 60f;   // Countdown: başlangıç süresi
    [SerializeField] private bool autoStart = true;

    [Header("UI")]
    [SerializeField] private TextMeshProUGUI timerText;

    [Header("Events")]
    public UnityEvent OnTimerEnd;                     // Inspector'dan bağla
    public UnityEvent<float> OnTimerTick;             // Her saniyede çağrılır

    // ─── Durum ────────────────────────────────────────────────────────────────
    public float CurrentTime  { get; private set; }
    public bool  IsRunning    { get; private set; }
    public float NormalizedTime => startTime > 0 ? CurrentTime / startTime : 0f; // 0-1 (cooldown UI için)

    private float _lastTickSecond;

    private void Start()
    {
        CurrentTime = mode == TimerMode.Countdown ? startTime : 0f;
        if (autoStart) StartTimer();
        UpdateUI();
    }

    private void Update()
    {
        if (!IsRunning) return;

        if (mode == TimerMode.Countdown)
        {
            CurrentTime -= Time.deltaTime;
            if (CurrentTime <= 0f)
            {
                CurrentTime = 0f;
                StopTimer();
                OnTimerEnd?.Invoke();
            }
        }
        else // Stopwatch
        {
            CurrentTime += Time.deltaTime;
        }

        // Saniye bazlı tick event
        if (Mathf.Floor(CurrentTime) != Mathf.Floor(_lastTickSecond))
        {
            _lastTickSecond = CurrentTime;
            OnTimerTick?.Invoke(CurrentTime);
        }

        UpdateUI();
    }

    // ─── Public API ───────────────────────────────────────────────────────────

    public void StartTimer()  { IsRunning = true; }
    public void StopTimer()   { IsRunning = false; }
    public void PauseTimer()  { IsRunning = false; }
    public void ResumeTimer() { IsRunning = true; }

    public void ResetTimer()
    {
        CurrentTime = mode == TimerMode.Countdown ? startTime : 0f;
        _lastTickSecond = CurrentTime;
        UpdateUI();
    }

    // ─── UI ───────────────────────────────────────────────────────────────────

    private void UpdateUI()
    {
        if (timerText == null) return;
        TimeSpan ts = TimeSpan.FromSeconds(CurrentTime);
        timerText.text = ts.ToString(@"mm\:ss");

        // Son 10 saniyede kırmızı yap
        if (mode == TimerMode.Countdown)
            timerText.color = CurrentTime <= 10f ? Color.red : Color.white;
    }
}

using UnityEngine;

/// <summary>
/// Minimap kamerasını takip ettiren bileşen.
/// Minimap Camera objesine ekle.
/// </summary>
public class MinimapCamera : MonoBehaviour
{
    [Header("Takip")]
    [SerializeField] private Transform target;      // Genellikle oyuncu
    [SerializeField] private float height = 20f;    // Kameranın yüksekliği
    [SerializeField] private bool followRotation = false; // Kamera oyuncuyla dönsün mü?

    private void LateUpdate()
    {
        if (target == null) return;

        // X ve Z'yi takip et, Y'yi sabit tut
        Vector3 pos = target.position;
        pos.y = target.position.y + height;
        transform.position = pos;

        if (followRotation)
            transform.rotation = Quaternion.Euler(90f, target.eulerAngles.y, 0f);
        else
            transform.rotation = Quaternion.Euler(90f, 0f, 0f); // Sabit kuzey yukarı
    }
}

/// <summary>
/// Minimap üzerinde görünecek ikon.
/// Oyuncu, düşman, toplanabilir gibi her nesneye ekle.
/// </summary>
public class MinimapIcon : MonoBehaviour
{
