/// <summary>
/// NavMeshAgent tabanlı düşman/NPC takip sistemi.
/// Gereksinim: NavMesh baked, NavMeshAgent component eklendi.
/// </summary>
[RequireComponent(typeof(NavMeshAgent))]
public class NavMeshEnemy : MonoBehaviour
{
    [Header("Hedef")]
    [SerializeField] private Transform target;          // Genellikle oyuncu
    [SerializeField] private float updateInterval = 0.2f; // Yol yenileme sıklığı (saniye)

    [Header("Saldırı Menzili")]
    [SerializeField] private float attackRange = 2f;
    [SerializeField] private float chaseRange = 15f;

    private NavMeshAgent _agent;
    private float _nextUpdateTime;

    private void Awake()
    {
        _agent = GetComponent<NavMeshAgent>();
    }

    private void Update()
    {
        if (target == null) return;

        float dist = Vector3.Distance(transform.position, target.position);

        if (dist > chaseRange)
        {
            _agent.isStopped = true;  // Menzil dışı — dur
            return;
        }

        if (dist <= attackRange)
        {
            _agent.isStopped = true;
            Attack();
            return;
        }

        // Kovalama — her updateInterval saniyede yolu güncelle
        _agent.isStopped = false;
        if (Time.time >= _nextUpdateTime)
        {
            _agent.SetDestination(target.position);
            _nextUpdateTime = Time.time + updateInterval;
        }
    }

    private void Attack()
    {
        // Saldırı mantığını buraya ekle
        Debug.Log($"{name} saldırıyor!");
    }
}

// ═══════════════════════════════════════════════════════════════════
// SEÇENEK 2: Basit A* Grid — 2D top-down / dinamik engeller için
// ═══════════════════════════════════════════════════════════════════

/// <summary>
/// Grid node — A* için.
/// </summary>
public class Node
{
    public bool   walkable;
    public Vector3 worldPos;
    public int    gridX, gridY;
    public int    gCost, hCost;   // g = baştan, h = hedefe tahmini
    public Node   parent;

    public int fCost => gCost + hCost;

    public Node(bool walkable, Vector3 worldPos, int gridX, int gridY)
    {
        this.walkable = walkable;
        this.worldPos = worldPos;
        this.gridX    = gridX;
        this.gridY    = gridY;
    }
}

/// <summary>
/// Basit A* Pathfinder — 2D top-down için.
/// Kullanım: var path = AStarPathfinder.FindPath(start, end, grid);
/// </summary>
public static class AStarPathfinder
{
    public static System.Collections.Generic.List<Node> FindPath(Node start, Node target, Node[,] grid)
    {
        var open   = new System.Collections.Generic.List<Node> { start };
        var closed = new System.Collections.Generic.HashSet<Node>();

        while (open.Count > 0)
        {
            // En düşük fCost'lu node'u seç
            Node current = open[0];
            for (int i = 1; i < open.Count; i++)
                if (open[i].fCost < current.fCost ||
                   (open[i].fCost == current.fCost && open[i].hCost < current.hCost))
                    current = open[i];

            open.Remove(current);
            closed.Add(current);

            if (current == target) return RetracePath(start, target);

            foreach (var neighbour in GetNeighbours(current, grid))
            {
                if (!neighbour.walkable || closed.Contains(neighbour)) continue;

                int newCost = current.gCost + GetDistance(current, neighbour);
                if (newCost < neighbour.gCost || !open.Contains(neighbour))
                {
                    neighbour.gCost  = newCost;
                    neighbour.hCost  = GetDistance(neighbour, target);
                    neighbour.parent = current;
                    if (!open.Contains(neighbour)) open.Add(neighbour);
                }
            }
        }
        return null; // Yol bulunamadı
    }

    private static System.Collections.Generic.List<Node> RetracePath(Node start, Node end)
    {
        var path    = new System.Collections.Generic.List<Node>();
        Node current = end;
        while (current != start) { path.Add(current); current = current.parent; }
        path.Reverse();
        return path;
    }

    private static int GetDistance(Node a, Node b)
    {
        int dx = Mathf.Abs(a.gridX - b.gridX);
        int dy = Mathf.Abs(a.gridY - b.gridY);
        // Diagonal: 14, düz: 10 (sqrt(2) ≈ 1.41 → tam sayı)
        return dx > dy ? 14 * dy + 10 * (dx - dy) : 14 * dx + 10 * (dy - dx);
    }

    private static System.Collections.Generic.List<Node> GetNeighbours(Node node, Node[,] grid)
    {
        var neighbours = new System.Collections.Generic.List<Node>();
        int w = grid.GetLength(0), h = grid.GetLength(1);
        for (int x = -1; x <= 1; x++)
        for (int y = -1; y <= 1; y++)
        {
            if (x == 0 && y == 0) continue;
            int nx = node.gridX + x, ny = node.gridY + y;
            if (nx >= 0 && nx < w && ny >= 0 && ny < h)
                neighbours.Add(grid[nx, ny]);
        }
        return neighbours;
    }
}
